import { execSync } from 'child_process';
import fs from 'fs';
const W='';
const FILES={
 'includes/class-pet-profile.php':'',
 'includes/class-pet-dashboard.php':'',
 'assets/pet-form.js':'',
 'assets/pet-profile.js':'',
 'assets/account.css':''
};
const TOKG=process.env.GH_TOKEN, REPO=process.env.GH_REPO||'raimis079-creator/petshop-bridge';
const U=process.env.WP_USER||'', P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const AUTH='-u "'+U+':'+P+'"';
function wj(m,path,body){fs.writeFileSync('/tmp/wb.json', JSON.stringify(body));
  return execSync('curl -sk '+AUTH+' -X '+m+' -H "Content-Type: application/json" --data-binary @/tmp/wb.json "https://dev.avesa.lt/wp-json/'+path+'"',{maxBuffer:50*1024*1024,timeout:70000}).toString();}
function putB64(name,b64){const u='https://api.github.com/repos/'+REPO+'/contents/screenshots/'+name;let s='';
 for(let i=0;i<5;i++){try{const j=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+TOKG+'" "'+u+'?n='+Math.random()+'"',{maxBuffer:50*1024*1024}).toString());if(j.sha)s=j.sha;}catch(e){}
  fs.writeFileSync('/tmp/pj.json',JSON.stringify({message:'r',content:b64,...(s?{sha:s}:{})}));
  const c=execSync('curl -s -o /dev/null -w "%{http_code}" -X PUT -H "Authorization: Bearer '+TOKG+'" -d @/tmp/pj.json "'+u+'"',{maxBuffer:50*1024*1024}).toString().trim();
  if(c==='200'||c==='201')return c; execSync('sleep 2');}return 'fail';}
const o={};
// 1) PHP lint runner'yje
try{
  for(const rel of Object.keys(FILES)){
    if(!rel.endsWith('.php')) continue;
    const tmp='/tmp/lint_'+rel.replace(/[\/]/g,'_');
    fs.writeFileSync(tmp, Buffer.from(FILES[rel],'base64'));
    const r=execSync('php -l '+tmp+' 2>&1').toString();
    o['lint_'+rel]=r.trim().slice(0,120);
    if(!/No syntax errors/.test(r)) { o.abort='LINT FAIL '+rel; putB64('dep218.json', Buffer.from(JSON.stringify(o)).toString('base64')); process.exit(0); }
  }
}catch(e){ o.abort='LINT ERR '+String(e).slice(0,200); putB64('dep218.json', Buffer.from(JSON.stringify(o)).toString('base64')); process.exit(0); }
// 2) writer snippet
const mk=wj('POST','code-snippets/v1/snippets',{name:'DEP218 (temp)',code:Buffer.from(W,'base64').toString('utf8'),scope:'front-end',active:true,priority:5});
let sid; try{sid=JSON.parse(mk).id;}catch(e){ o.mkerr=String(mk).slice(0,200); }
execSync('sleep 3');
// 3) POST failai
fs.writeFileSync('/tmp/payload.json', JSON.stringify({files:FILES}));
try{
  const r=execSync('curl -sk -X POST -H "Content-Type: application/json" --data-binary @/tmp/payload.json "https://dev.avesa.lt/?ps_dep218=Dp218x"',{maxBuffer:20*1024*1024,timeout:90000}).toString();
  o.write=r.slice(r.indexOf('{'), r.lastIndexOf('}')+1).slice(0,900);
}catch(e){ o.write='ERR '+String(e).slice(0,200); }
// 4) cleanup snippet
if(sid){ try{wj('POST','code-snippets/v1/snippets/'+sid,{active:false});}catch(e){} try{execSync('curl -sk '+AUTH+' -X DELETE "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/'+sid+'"');}catch(e){} }
// 5) fatal check
try{ o.home=execSync('curl -sk -o /dev/null -w "%{http_code}" "https://dev.avesa.lt/"').toString(); }catch(e){ o.home='ERR'; }
try{ o.rest=execSync('curl -sk -o /dev/null -w "%{http_code}" "https://dev.avesa.lt/wp-json/"').toString(); }catch(e){ o.rest='ERR'; }
putB64('dep218.json', Buffer.from(JSON.stringify(o)).toString('base64'));
console.log('done');
